ВЫБРАТЬ ВЫБОР КОГДА EmitentList.country_oksm = 643 ТОГДА ИСТИНА ИНАЧЕ ЛОЖЬ КОНЕЦ КАК ЭтоRU, EmitentList.fininstid КАК fininstid, EmitentList.issuer_nrd КАК issuer_nrd, EmitentList.shortname_rus_nrd КАК shortname_rus_nrd, EmitentList.shortname_rus КАК shortname_rus, EmitentList.country_oksm КАК country_oksm, EmitentList.fullname_rus_nrd КАК fullname_rus_nrd, EmitentList.fullname_rus КАК fullname_rus, EmitentList.inn КАК inn, EmitentList.inn_fle КАК inn_fle, EmitentList.tin КАК tin, EmitentList.kpp КАК kpp, EmitentList.okpo КАК okpo, EmitentList.ogrn КАК ogrn, EmitentList.fullname_eng_nrd КАК fullname_eng_nrd, EmitentList.shortname_eng КАК shortname_eng, EmitentList.state_reg_name КАК state_reg_name, EmitentList.okopf КАК okopf, EmitentList.okogu КАК okogu, EmitentList.okved КАК okved, EmitentList.update_date КАК update_date_ДАТА, EmitentList.state_reg_date КАК state_reg_date_ДАТА, EmitentList.egrul_date КАК egrul_date_ДАТА, EmitentList.egrul_organ_name КАК egrul_organ_name, EmitentList.post_address КАК post_address, EmitentList.legal_address КАК legal_address, EmitentList.e_mail КАК e_mail, EmitentList.phone КАК phone, EmitentList.reg_date КАК reg_date_ДАТА, EmitentList.primary_reg_date КАК primary_reg_date_ДАТА, EmitentList.reg_code КАК reg_code, EmitentList.sector4212u КАК sector4212u, EmitentList.lei_code КАК lei_code, EmitentList.credit_cmp КАК credit_cmp, EmitentList.br_fcsm_reg_code КАК br_fcsm_reg_code, EmitentList.state_reg_num КАК state_reg_num, EmitentList.state_reg_number КАК state_reg_number, ЛОЖЬ КАК ИзменилсяСамЭмитент ПОМЕСТИТЬ ДанныеRuData ИЗ ВТ_ТаблицаЭмитентовЗагружаемыхЦБ КАК EmitentList
ОБЪЕДИНИТЬ ВСЕ
ВЫБРАТЬ ВЫБОР КОГДА EmitentList.country_oksm = 643 ТОГДА ИСТИНА ИНАЧЕ ЛОЖЬ КОНЕЦ, EmitentList.fininstid, EmitentList.issuer_nrd, EmitentList.shortname_rus_nrd, EmitentList.shortname_rus, EmitentList.country_oksm, EmitentList.fullname_rus_nrd, EmitentList.fullname_rus, EmitentList.inn, EmitentList.inn_fle, EmitentList.tin, EmitentList.kpp, EmitentList.okpo, EmitentList.ogrn, EmitentList.fullname_eng_nrd, EmitentList.shortname_eng, EmitentList.state_reg_name, EmitentList.okopf, EmitentList.okogu, EmitentList.okved, EmitentList.update_date, EmitentList.state_reg_date, EmitentList.egrul_date, EmitentList.egrul_organ_name, EmitentList.post_address, EmitentList.legal_address, EmitentList.e_mail, EmitentList.phone, EmitentList.reg_date, EmitentList.primary_reg_date, EmitentList.reg_code, EmitentList.sector4212u, EmitentList.lei_code, EmitentList.credit_cmp, EmitentList.br_fcsm_reg_code, EmitentList.state_reg_num, EmitentList.state_reg_number, ИСТИНА ИЗ ВТ_ТаблицаИзменившихсяЭмитентов КАК EmitentList ЛЕВОЕ СОЕДИНЕНИЕ ВТ_ТаблицаЭмитентовЗагружаемыхЦБ КАК ВТ_ТаблицаЭмитентовЗагружаемыхЦБ ПО EmitentList.fininstid = ВТ_ТаблицаЭмитентовЗагружаемыхЦБ.fininstid ГДЕ ВТ_ТаблицаЭмитентовЗагружаемыхЦБ.fininstid ЕСТЬ NULL ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ ДанныеRuData.fininstid КАК fininstid, ДанныеRuData.issuer_nrd КАК issuer_nrd, ДанныеRuData.shortname_rus_nrd КАК shortname_rus_nrd, ДанныеRuData.shortname_rus КАК shortname_rus, ДанныеRuData.inn КАК inn, ДанныеRuData.ЭтоRU КАК ЭтоRU, МАКСИМУМ(ДанныеRuData.ИзменилсяСамЭмитент) КАК ИзменилсяСамЭмитент, МАКСИМУМ(ЕСТЬNULL(КодыЗагрузкиRuData.Код, "")) КАК КодЗагрузкиRuData, МАКСИМУМ(ЕСТЬNULL(КодыЗагрузкиНДЦ.Код, "")) КАК КодЗагрузкиНДЦ, МАКСИМУМ(ЕСТЬNULL(КодыЗагрузкиRuData.Владелец, ЕСТЬNULL(КодыЗагрузкиНДЦ.Владелец, НЕОПРЕДЕЛЕНО))) КАК ЮрЛицо ПОМЕСТИТЬ КлючевыеПоляRuData ИЗ ДанныеRuData КАК ДанныеRuData ЛЕВОЕ СОЕДИНЕНИЕ Справочник.ЮридическиеЛица КАК ЮрЛицо1 ВНУТРЕННЕЕ СОЕДИНЕНИЕ Справочник.КодыЗагрузки КАК КодыЗагрузкиRuData ПО ЮрЛицо1.Ссылка = КодыЗагрузкиRuData.Владелец И (НЕ КодыЗагрузкиRuData.ПометкаУдаления) И (КодыЗагрузкиRuData.Биржа = &КлассификаторRuData) И (&ТекущаяДатаСеанса >= КодыЗагрузкиRuData.ДатаНачалаДействия) И (КодыЗагрузкиRuData.ДатаОкончанияДействия = ДАТАВРЕМЯ(1, 1, 1) ИЛИ &ТекущаяДатаСеанса < КодыЗагрузкиRuData.ДатаОкончанияДействия) ПО (ДанныеRuData.fininstid = КодыЗагрузкиRuData.Код) И (НЕ ЮрЛицо1.ПометкаУдаления) ЛЕВОЕ СОЕДИНЕНИЕ Справочник.ЮридическиеЛица КАК ЮрЛицо2 ВНУТРЕННЕЕ СОЕДИНЕНИЕ Справочник.КодыЗагрузки КАК КодыЗагрузкиНДЦ ПО ЮрЛицо2.Ссылка = КодыЗагрузкиНДЦ.Владелец И (НЕ КодыЗагрузкиНДЦ.ПометкаУдаления) И (КодыЗагрузкиНДЦ.Биржа = &КлассификаторНДЦ) И (&ТекущаяДатаСеанса >= КодыЗагрузкиНДЦ.ДатаНачалаДействия) И (КодыЗагрузкиНДЦ.ДатаОкончанияДействия = ДАТАВРЕМЯ(1, 1, 1) ИЛИ &ТекущаяДатаСеанса < КодыЗагрузкиНДЦ.ДатаОкончанияДействия) ПО (ДанныеRuData.issuer_nrd = КодыЗагрузкиНДЦ.Код) И (НЕ ЮрЛицо2.ПометкаУдаления) И (ВЫБОР КОГДА &ЭтоПервоначальнаяЗагрузка ТОГДА ИСТИНА ИНАЧЕ ЮрЛицо1.Ссылка = ЮрЛицо2.Ссылка КОНЕЦ)
СГРУППИРОВАТЬ ПО ДанныеRuData.fininstid, ДанныеRuData.issuer_nrd, ДанныеRuData.shortname_rus_nrd, ДанныеRuData.shortname_rus, ДанныеRuData.inn, ДанныеRuData.ЭтоRU ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ КлючевыеПоляRuData.fininstid КАК fininstid, КлючевыеПоляRuData.issuer_nrd КАК issuer_nrd, КлючевыеПоляRuData.shortname_rus_nrd КАК shortname_rus_nrd, КлючевыеПоляRuData.shortname_rus КАК shortname_rus, КлючевыеПоляRuData.КодЗагрузкиRuData КАК КодЗагрузкиRuData, КлючевыеПоляRuData.КодЗагрузкиНДЦ КАК КодЗагрузкиНДЦ, МАКСИМУМ(КлючевыеПоляRuData.ИзменилсяСамЭмитент) КАК ИзменилсяСамЭмитент, МАКСИМУМ(ЕСТЬNULL(ЕСТЬNULL(ЮридическиеЛицаПоИНН.Ссылка, ЮридическиеЛицаПоНаименованию.Ссылка), КлючевыеПоляRuData.ЮрЛицо)) КАК ЮрЛицо ПОМЕСТИТЬ КЛЮЧ ИЗ КлючевыеПоляRuData КАК КлючевыеПоляRuData ЛЕВОЕ СОЕДИНЕНИЕ Справочник.ЮридическиеЛица КАК ЮридическиеЛицаПоИНН ПО (КлючевыеПоляRuData.ЮрЛицо = НЕОПРЕДЕЛЕНО) И (&ЭтоПервоначальнаяЗагрузка) И КлючевыеПоляRuData.inn = ЮридическиеЛицаПоИНН.ИНН И (ЮридическиеЛицаПоИНН.ИНН <> "") И (КлючевыеПоляRuData.inn <> "") И (НЕ ЮридическиеЛицаПоИНН.Наименование = "") И (НЕ ЮридическиеЛицаПоИНН.ПометкаУдаления) ЛЕВОЕ СОЕДИНЕНИЕ Справочник.ЮридическиеЛица КАК ЮридическиеЛицаПоНаименованию ПО (КлючевыеПоляRuData.ЮрЛицо = НЕОПРЕДЕЛЕНО) И (&ЭтоПервоначальнаяЗагрузка) И (ВЫБОР КОГДА КлючевыеПоляRuData.shortname_rus_nrd = "" ТОГДА КлючевыеПоляRuData.shortname_rus ИНАЧЕ КлючевыеПоляRuData.shortname_rus_nrd КОНЕЦ = ЮридическиеЛицаПоНаименованию.Наименование) И (ЮридическиеЛицаПоИНН.ИНН = "") И (КлючевыеПоляRuData.inn = "") И (НЕ ЮридическиеЛицаПоНаименованию.Наименование = "") И (НЕ ЮридическиеЛицаПоНаименованию.ПометкаУдаления)
СГРУППИРОВАТЬ ПО КлючевыеПоляRuData.fininstid, КлючевыеПоляRuData.issuer_nrd, КлючевыеПоляRuData.shortname_rus_nrd, КлючевыеПоляRuData.shortname_rus, КлючевыеПоляRuData.КодЗагрузкиRuData, КлючевыеПоляRuData.КодЗагрузкиНДЦ ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ ЮридическиеЛица.Ссылка КАК ЮрЛицо ПОМЕСТИТЬ ВТ_ИзменившиесяЮрлицаСАктуальнымиБумагами ИЗ Справочник.ЦенныеБумаги КАК ЦенныеБумаги ВНУТРЕННЕЕ СОЕДИНЕНИЕ Справочник.Контрагенты КАК Контрагенты ПО ЦенныеБумаги.Эмитент = Контрагенты.Ссылка ВНУТРЕННЕЕ СОЕДИНЕНИЕ Справочник.ЮридическиеЛица КАК ЮридическиеЛица ПО (Контрагенты.ЮридическиеФизическиеЛица = ЮридическиеЛица.Ссылка) ВНУТРЕННЕЕ СОЕДИНЕНИЕ КЛЮЧ КАК КЛЮЧ ПО (КЛЮЧ.ЮрЛицо = ЮридическиеЛица.Ссылка) И (КЛЮЧ.ИзменилсяСамЭмитент) ГДЕ ЦенныеБумаги.СтатусRuData В(&СтатусыАктуальныхЦБ)
СГРУППИРОВАТЬ ПО ЮридическиеЛица.Ссылка ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ ДанныеRuData.ЭтоRU КАК ЭтоRU, ДанныеRuData.fininstid КАК fininstid, ДанныеRuData.issuer_nrd КАК issuer_nrd, ДанныеRuData.shortname_rus_nrd КАК shortname_rus_nrd, ДанныеRuData.shortname_rus КАК shortname_rus, ДанныеRuData.country_oksm КАК country_oksm, ДанныеRuData.fullname_rus_nrd КАК fullname_rus_nrd, ДанныеRuData.fullname_rus КАК fullname_rus, ДанныеRuData.inn КАК inn, ДанныеRuData.inn_fle КАК inn_fle, ДанныеRuData.tin КАК tin, ДанныеRuData.kpp КАК kpp, ДанныеRuData.okpo КАК okpo, ДанныеRuData.ogrn КАК ogrn, ДанныеRuData.fullname_eng_nrd КАК fullname_eng_nrd, ДанныеRuData.shortname_eng КАК shortname_eng, ДанныеRuData.state_reg_name КАК state_reg_name, ДанныеRuData.okopf КАК okopf, ДанныеRuData.okogu КАК okogu, ДанныеRuData.okved КАК okved, ДанныеRuData.update_date_ДАТА КАК update_date_ДАТА, ДанныеRuData.state_reg_date_ДАТА КАК state_reg_date_ДАТА, ДанныеRuData.egrul_date_ДАТА КАК egrul_date_ДАТА, ДанныеRuData.egrul_organ_name КАК egrul_organ_name, ДанныеRuData.post_address КАК post_address, ДанныеRuData.legal_address КАК legal_address, ДанныеRuData.e_mail КАК e_mail, ДанныеRuData.phone КАК phone, ДанныеRuData.reg_date_ДАТА КАК reg_date_ДАТА, ДанныеRuData.primary_reg_date_ДАТА КАК primary_reg_date_ДАТА, ДанныеRuData.reg_code КАК reg_code, ДанныеRuData.sector4212u КАК sector4212u, ДанныеRuData.lei_code КАК lei_code, ДанныеRuData.credit_cmp КАК credit_cmp, ДанныеRuData.br_fcsm_reg_code КАК br_fcsm_reg_code, ДанныеRuData.state_reg_num КАК state_reg_num, ДанныеRuData.state_reg_number КАК state_reg_number, КЛЮЧ.ЮрЛицо КАК ЮрЛицо, КЛЮЧ.ЮрЛицо = НЕОПРЕДЕЛЕНО КАК ЭтоНовыйЭмитент, КЛЮЧ.КодЗагрузкиRuData КАК КодЗагрузкиRuData, КЛЮЧ.КодЗагрузкиНДЦ КАК КодЗагрузкиНДЦ ИЗ ДанныеRuData КАК ДанныеRuData ВНУТРЕННЕЕ СОЕДИНЕНИЕ КЛЮЧ КАК КЛЮЧ ПО ДанныеRuData.fininstid = КЛЮЧ.fininstid ЛЕВОЕ СОЕДИНЕНИЕ ВТ_ИзменившиесяЮрлицаСАктуальнымиБумагами КАК ВТ_ИзменившиесяЮрлицаСАктуальнымиБумагами ПО (КЛЮЧ.ЮрЛицо = ВТ_ИзменившиесяЮрлицаСАктуальнымиБумагами.ЮрЛицо) ГДЕ (НЕ ДанныеRuData.ИзменилсяСамЭмитент ИЛИ НЕ ВТ_ИзменившиесяЮрлицаСАктуальнымиБумагами.ЮрЛицо ЕСТЬ NULL)
